const data = $getWorkflowStaticData('global');

const runId = $json.runId || 'default';

// Namespacing po runId da se ne miješaju izvršenja
data.runs ??= {};
data.runs[runId] ??= {};

const run = data.runs[runId];

// Init samo jednom
run.ledger ??= {
  pages: {},        // pageNo -> { pageNo, accountNo, text }
  accounts: {},     // accountNo -> matching state (unmatched/pairs/seen)
  entries: []       // (opcionalno) svi parsirani redovi
};

return items;

const raw =
  $json.text ||
  $json.content ||
  $json.raw ||
  $json.pageText ||
  '';

function normalize(text) {
  return String(text)
    .replace(/\r/g, '')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{2,}/g, '\n')
    .trim();
}

return { pageText: normalize(raw) };

/**
 * Extract Ledger Rows - ORIGINAL + SIMPLE FIX
 * MODE: Run Once for Each Item
 */

function normSpaces(s) {
  return (s ?? '').toString().replace(/\s+/g, ' ').trim();
}
function isTxnLine(line) {
  return /^\d{2}\.\d{2}\.\d{4}\b/.test(line);
}
function isDetailLine(line) {
  return /^\d+\s+\d+\s+\d+\s+[A-ZČĆŽŠĐ]{2,}\s+\d+/.test(line.trim());
}
function parseAmountToken(tok) {
  if (!tok) return null;
  const s = String(tok).trim();
  if (!/^-?\d{1,3}(\.\d{3})*,\d{2}$/.test(s) && !/^-?\d+,\d{2}$/.test(s)) return null;
  const cleaned = s.replace(/\./g, '').replace(',', '.');
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
}
function lastAmountInText(desc) {
  const m = String(desc || '').match(/(-?\d{1,3}(?:\.\d{3})*,\d{2}|-?\d+,\d{2})(?!.*\d)/);
  if (!m) return null;
  return parseAmountToken(m[1]);
}
function isLikelyBrokenDesc(s) {
  const t = (s || '').trim();
  return /^[0-9]{2,6}$/.test(t) || t.length < 20;
}
function pickTextFromJson(j) {
  if (!j) return '';
  return (j.pageText ?? j.text ?? j.fullText ?? j.data ?? j.content ?? '');
}

// ---- workflow static data (robust) ----
let sd = {};
try {
  if (typeof $getWorkflowStaticData === 'function') {
    sd = $getWorkflowStaticData('global') || {};
  } else if (typeof $workflow !== 'undefined' && $workflow?.staticData) {
    sd = $workflow.staticData;
  }
} catch (e) {
  sd = {};
}

sd.__ledger = sd.__ledger || {};
sd.__ledger.lastAccountNo = sd.__ledger.lastAccountNo || null;
sd.__ledger.lastAccountName = sd.__ledger.lastAccountName || null;

// ---- input text ----
const raw = String(pickTextFromJson($json) ?? '');
if (!raw.trim()) {
  return {
    rows: [],
    rowCount: 0,
    warning: 'No pageText/text found on input item',
    inputKeys: Object.keys($json || {}),
  };
}

// ---- parse ----
const lines = raw
  .split('\n')
  .map(l => l.replace(/\r/g, '').trim())
  .filter(Boolean);

let currentAccountNo = sd.__ledger.lastAccountNo;
let currentAccountName = sd.__ledger.lastAccountName;

const rows = [];

for (let idx = 0; idx < lines.length; idx++) {
  const line = lines[idx];
  const normalizedLine = normSpaces(line);

  // header konta: "Račun: 232110: Službena putovanja"
  const mh =
    normalizedLine.match(/^Račun\s*:\s*([0-9]+)\s*:\s*(.+)$/i) ||
    normalizedLine.match(/^Racun\s*:\s*([0-9]+)\s*:\s*(.+)$/i);

  if (mh) {
    currentAccountNo = mh[1];
    currentAccountName = (mh[2] || '').trim();
    sd.__ledger.lastAccountNo = currentAccountNo;
    sd.__ledger.lastAccountName = currentAccountName;
    continue;
  }

  if (!isTxnLine(line)) continue;

  const accountNo = currentAccountNo || 'UNKNOWN_ACCOUNT';
  const accountName = currentAccountName || '';

  const parts = line.split(' ').filter(Boolean);
  const date = parts[0];

  // iznosi s kraja (max 3)
  const amounts = [];
  let cutIndex = parts.length;

  for (let i = parts.length - 1; i >= 1; i--) {
    const a = parseAmountToken(parts[i]);
    if (a == null) break;
    amounts.unshift(a);
    cutIndex = i;
    if (amounts.length === 3) break;
  }

  if (amounts.length === 0) continue;

  let description = parts.slice(1, cutIndex).join(' ').trim();

  // ============================================================================
  // SIMPLE FIX: ako je description kratak, spoji s prethodnom linijom
  // ============================================================================
  if (isLikelyBrokenDesc(description)) {
    // Provjeri prethodnu liniju
    if (idx > 0) {
      const prevLine = lines[idx - 1];

      // Ako prethodna linija NIJE detail linija i NIJE nova transakcija (s datumom)
      if (!isDetailLine(prevLine)) {
        // Ako prethodna linija IMA datum - to je početak trenutne transakcije
        if (isTxnLine(prevLine)) {
          // Izvuci opis iz prethodne linije (bez datuma i bez iznosa)
          const prevParts = prevLine.split(' ').filter(Boolean);
          const prevDesc = prevParts.slice(1).join(' ').trim();

          // Provjeri ima li prethodna linija iznose
          const prevAmounts = [];
          for (let i = prevParts.length - 1; i >= 1; i--) {
            if (parseAmountToken(prevParts[i])) {
              prevAmounts.unshift(prevParts[i]);
            } else {
              break;
            }
          }

          // Ako prethodna linija NEMA iznose, cijeli ostatak je opis
          if (prevAmounts.length === 0 && prevDesc) {
            description = prevDesc + ' ' + description;
          }
        } else {
          // Prethodna linija je nastavak opisa (nema datum)
          description = normSpaces(prevLine) + ' ' + description;
        }
      }
    }
  }
  // ============================================================================

  let duguje = 0;
  let potrazuje = 0;
  let saldo = null;

  if (amounts.length === 3) {
    duguje = Math.abs(amounts[0] ?? 0);
    potrazuje = Math.abs(amounts[1] ?? 0);
    saldo = amounts[2] ?? null;
  } else if (amounts.length === 2) {
    saldo = amounts[1] ?? null;

    const isIzvod =
      /\bIzvod\b/i.test(description) ||
      /\b-\s*(Račun|Racun|RN)\b/i.test(description);

    if (isIzvod) {
      duguje = Math.abs(amounts[0] ?? 0);
      potrazuje = 0;

      if (!duguje) {
        const fromDesc = lastAmountInText(description);
        if (fromDesc != null) duguje = Math.abs(fromDesc);
      }
    } else {
      duguje = 0;
      potrazuje = Math.abs(amounts[0] ?? 0);

      if (!potrazuje) {
        const fromDesc = lastAmountInText(description);
        if (fromDesc != null) potrazuje = Math.abs(fromDesc);
      }
    }
  } else {
    continue;
  }

  rows.push({
    accountNo,
    accountName,
    lineNo: idx + 1,
    rawLine: normalizedLine,
    date,
    description,
    duguje,
    potrazuje,
    saldo,
  });
}

// IMPORTANT: in "Run once for each item" -> return OBJECT (not array, not {json:{...}})
return {
  rows,
  rowCount: rows.length,
  debug: {
    lastAccountNo: sd.__ledger.lastAccountNo,
    lastAccountName: sd.__ledger.lastAccountName,
    inputKeys: Object.keys($json || {}),
  }
};

const items = $input.all();

function norm(s) {
  return (s ?? '').toString().replace(/\s+/g, ' ').trim();
}
function dateKey(d) {
  const [dd, mm, yyyy] = String(d || '').split('.');
  if (!yyyy) return String(d || '');
  return `${yyyy}${mm}${dd}`;
}

// pokušaj dohvatiti rows iz raznih mogućih mjesta
function getRows(it) {
  // standardno: it.json.rows
  if (it && it.json && Array.isArray(it.json.rows)) return it.json.rows;

  // fallback: neki slučajevi gdje node vrati “plain object”
  if (it && Array.isArray(it.rows)) return it.rows;

  // fallback: ako je netko stavio rows kao string (ne bi trebao)
  return [];
}

const byAcc = {};
let inputItems = items.length;
let totalRowsSeen = 0;
let sampleKeys = null;

for (const it of items) {
  if (!sampleKeys && it && it.json) sampleKeys = Object.keys(it.json);

  const rows = getRows(it);
  totalRowsSeen += rows.length;

  for (const r of rows) {
    const acc = r.accountNo || 'UNKNOWN_ACCOUNT';
    byAcc[acc] = byAcc[acc] || { accountName: r.accountName || '', rows: [] };
    if (!byAcc[acc].accountName && r.accountName) byAcc[acc].accountName = r.accountName;
    byAcc[acc].rows.push(r);
  }
}

const out = [];

for (const [accountNo, bucket] of Object.entries(byAcc)) {
  const rows = bucket.rows;

  rows.sort((a, b) => {
    const da = dateKey(a.date);
    const db = dateKey(b.date);
    if (da !== db) return da.localeCompare(db);
    return (a.lineNo ?? 0) - (b.lineNo ?? 0);
  });

  // dedup (date + rawLine)
  const seen = new Set();
  const deduped = [];
  for (const r of rows) {
    const k = `${norm(r.date)}|${norm(r.rawLine).toLowerCase()}`;
    if (seen.has(k)) continue;
    seen.add(k);
    deduped.push(r);
  }

  out.push({
    json: {
      accountNo,
      accountName: bucket.accountName || '',
      rows: deduped,
      rowCount: deduped.length,
    }
  });
}

// ako je out prazan, vrati debug item da znaš zašto
if (out.length === 0) {
  return [{
    json: {
      error: "Group Accounts to Items: nisam našao nijedan row u input itemima.",
      hint: "Provjeri da 'Extract Ledger Rows' vraća rows po itemu. U n8n Code node-u najsigurnije je da Extract vrati: return [{ json: { rows } }];",
      inputItems,
      totalRowsSeen,
      sampleFirstItemKeys: sampleKeys,
      firstItemPreview: items[0]?.json ?? null,
    }
  }];
}

return out;

/**
 * Match + Report (per account) - kompatibilno za Format Output
 *
 * SPECIAL 239210:
 * - "obveza" = D red (duguje>0) koji u opisu ima MM/YYYY i nije IRA/URA
 * - suma = zbroj POTRAŽUJE samo IRA/URA redova tog mjeseca (prema date)
 * - ako suma == obveza => obveza + IRA/URA used
 * - inače: IRA/URA used (sakrij), obveza ostaje unmatched
 * - unmatched za 239210 prikazuje SAMO obveze, uz stupce period/suma/diff
 *
 * SPECIAL 239220:
 * - match D vs P po (PDV period + amount) ako postoji
 * - fallback: match po amount-only kad je jedinstveni 1:1
 *
 * SPECIAL 239540:
 * - group matcher: SUMMARY "Prijevoz MM/YY" (ili MM/YYYY) zatvara period ako se suma detaila poklapa
 * - u SUMU ulaze samo detail redovi koji sadrže riječ "prijevoz" (točno, ne "prijevoza")
 * - ako detail opis sadrži MM/YY ili MM/YYYY => mora biti baš taj period (sprječava 12/2024 da uđe u 01/2025)
 * - LOCK: svi detail redovi perioda koji ima summary se zaključaju da ih drugi matcheri ne pojedu
 *
 * IRA matching uklonjen (ne koristi se za parove).
 */

/**
 * ===== COMMON HELPERS + INPUT + SALDO + ENTRIES (STOP before match239210) =====
 * - NEMA duplog entries
 * - SALDO preferira eksplicitno Početno/Završno/Konačno/Zaključno stanje
 * - fallback: opening iz prvog saldo retka (saldo - net), ending iz zadnjeg saldo retka
 */

function norm(s) { return (s ?? "").toString().replace(/\s+/g, " ").trim(); }
function upper(s) { return norm(s).toUpperCase(); }
function toFixed2(n) { return Math.round((Number(n) + Number.EPSILON) * 100) / 100; }

function parseNum(x) {
  if (x === null || x === undefined) return 0;
  if (typeof x === "number") return Number.isFinite(x) ? x : 0;
  let s = String(x).trim();
  if (!s) return 0;
  s = s.replace(/\s+/g, "");
  if (s.includes(",")) {
    s = s.replace(/\./g, "");
    s = s.replace(",", ".");
  }
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

// DD.MM.YYYY (ili D.M.YYYY) => YYYYMM
function periodFromDate(dateStr) {
  const s = String(dateStr || "").trim();
  if (!s) return null;
  const m = s.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})\.?$/);
  if (!m) return null;
  const mm = String(m[2]).padStart(2, "0");
  const yyyy = m[3];
  return `${yyyy}${mm}`;
}

// DD.MM.YYYY => YYYYMMDD (za redoslijed / ključeve)
function parseDateKey(d) {
  const s = String(d || "").trim();
  const m = s.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})\.?$/);
  if (!m) return s;
  const dd = String(m[1]).padStart(2, "0");
  const mm = String(m[2]).padStart(2, "0");
  const yyyy = m[3];
  return `${yyyy}${mm}${dd}`;
}

// MM/YYYY ili M/YYYY => YYYYMM
function extractMonthYear(desc) {
  const t = norm(desc);
  const m = t.match(/\b([0-1]?\d)\/(20\d{2})\b/);
  if (!m) return null;
  const mm = String(m[1]).padStart(2, "0");
  const yyyy = m[2];
  return `${yyyy}${mm}`;
}

// MM/YY ili M/YY => YYYYMM (pretpostavka 20YY)
function extractMonthYearShort(desc) {
  const t = norm(desc);
  const m = t.match(/\b([0-1]?\d)\/(\d{2})\b/);
  if (!m) return null;
  const mm = String(m[1]).padStart(2, "0");
  const yyyy = `20${m[2]}`;
  return `${yyyy}${mm}`;
}

// PDV period helper (239220)
function extractPdvPeriodFlexible(desc) {
  return extractMonthYear(desc) || extractMonthYearShort(desc);
}

// IRA/URA redovi (239210)
function isIraUra(e) {
  const d = upper(e.description);
  return /\b(IRA|URA)\b/.test(d);
}

// "obveza" red za 239210
function isMonthlyObveza239210(e) {
  if (!(e.duguje > 0 && e.potrazuje === 0)) return false;
  if (isIraUra(e)) return false;
  return !!extractMonthYear(e.description);
}

function extractUR(desc) {
  const t = norm(desc);
  let m = t.match(/\bURR?\b\s*[:\-]?\s*(\d{2}\/\d{7,})\b/i);
  if (m) return m[1];
  m = t.match(/\bURR?\b\s*[:\-]?\s*(\d{2}\/\d{5,})\b/i);
  if (m) return m[1];
  m = t.match(/\bURR?\b\s*[:\-]?\s*(\d{2}\-\d{5,})\b/i);
  if (m) return m[1].replace("-", "/");
  return null;
}

function extractDocNo(desc) {
  const t = norm(desc);
  const m = t.match(/\b([0-9]{2}\/[0-9]{2,})\b/);
  return m ? m[1] : null;
}

function extractPN(desc) {
  const t = norm(desc);
  let m = t.match(/\bPN\s*([0-9]{2}\/[0-9]{1,4})\b/i);
  if (m) return `PN ${m[1]}`;
  m = t.match(/\bref\.?\s*pn\s*([0-9]{2}\/[0-9]{1,4})\b/i);
  if (m) return `PN ${m[1]}`;
  return null;
}

function extractPerson(desc) {
  const t = norm(desc);
  let m = t.match(/\b([A-ZČĆŽŠĐ][a-zčćžšđ]+(?:[-'][A-Za-zČĆŽŠĐčćžšđ]+)?)\s+([A-ZČĆŽŠĐ][a-zčćžšđ]+(?:[-'][A-Za-zČĆŽŠĐčćžšđ]+)?)\b/);
  if (m) return upper(`${m[1]} ${m[2]}`);
  m = t.match(/\b([A-ZČĆŽŠĐ]{2,}(?:[-'][A-ZČĆŽŠĐ]+)?)\s+([A-ZČĆŽŠĐ]{2,}(?:[-'][A-ZČĆŽŠĐ]+)?)\b/);
  if (m) return upper(`${m[1]} ${m[2]}`);
  return null;
}

function sideLabel(e) {
  if (e.duguje > 0 && e.potrazuje === 0) return "D";
  if (e.potrazuje > 0 && e.duguje === 0) return "P";
  if (e.duguje > 0 && e.potrazuje > 0) return "D+P";
  return "-";
}

function entryNet(e) { return toFixed2((e.duguje || 0) - (e.potrazuje || 0)); }
function moneyAbsAmount(e) { return toFixed2(Math.max(Math.abs(e.duguje || 0), Math.abs(e.potrazuje || 0))); }
function safeArray(x) { return Array.isArray(x) ? x : []; }

// INPUT
const input = $json || {};
const accountNo = String(input.accountNo || input.account || "UNKNOWN").trim();
const accountName = input.accountName || "";
const rows = safeArray(input.rows);

if (!rows.length) {
  return [{
    json: {
      accountNo, accountName,
      counts: { rows: 0, entries: 0, matches: 0, unmatched: 0 },
      saldo: { first: null, last: null, delta: null },
      unmatched: [],
      unmatchedSignedSum: 0,
      saldoCheck: { ok: false, reason: "no rows", diff: 0 }
    }
  }];
}

// ===== SALDO: preferiraj eksplicitne redove "Početno"/"Završno/Konačno/Zaključno stanje" =====
let openingSaldoFromRows = null;
let endingSaldoFromRows = null;

function isOpeningSaldoLine(descUpper) {
  return (descUpper.includes("POČETNO STANJE") || descUpper.includes("POCETNO STANJE"));
}

function isEndingSaldoLine(descUpper) {
  return (
    descUpper.includes("ZAVRŠNO STANJE") ||
    descUpper.includes("ZAVRSNO STANJE") ||
    descUpper.includes("KONAČNO STANJE") ||
    descUpper.includes("KONACNO STANJE") ||
    descUpper.includes("ZAKLJUČNO STANJE") ||
    descUpper.includes("ZAKLJUCNO STANJE")
  );
}

for (const r of rows) {
  const desc = norm(r.description || r.rawLine || "");
  const DU = upper(desc);

  if (isOpeningSaldoLine(DU)) {
    if (r.saldo !== null && r.saldo !== undefined && String(r.saldo).trim() !== "") {
      openingSaldoFromRows = parseNum(r.saldo);
    }
    continue;
  }

  if (isEndingSaldoLine(DU)) {
    if (r.saldo !== null && r.saldo !== undefined && String(r.saldo).trim() !== "") {
      endingSaldoFromRows = parseNum(r.saldo);
    }
    continue;
  }
}

// ===== build entries (SINGLE source of truth) =====
const entries = [];
for (const r of rows) {
  const desc = norm(r.description || r.rawLine || "");
  const DU = upper(desc);

  // preskoči saldo header linije
  if (isOpeningSaldoLine(DU)) continue;
  if (isEndingSaldoLine(DU)) continue;

  const duguje = parseNum(r.duguje);
  const potrazuje = parseNum(r.potrazuje);
  if (!(duguje || potrazuje)) continue;

  const e = {
    idx: entries.length,
    date: norm(r.date || ""),
    dateKey: parseDateKey(r.date || ""),
    description: desc,
    rawLine: norm(r.rawLine || ""),
    lineNo: (r.lineNo ?? null),

    duguje,
    potrazuje,
    saldo: (r.saldo === null || r.saldo === undefined || String(r.saldo).trim() === "")
      ? null
      : parseNum(r.saldo),
  };

  e.amount = moneyAbsAmount(e);
  e.net = entryNet(e);

  e.ur = extractUR(e.description);
  e.docNo = extractDocNo(e.description);
  e.pn = extractPN(e.description);
  e.person = extractPerson(e.description);

  e.periodDate = periodFromDate(e.date);
  e.periodDescLong = extractMonthYear(e.description);
  e.periodDescShort = extractMonthYearShort(e.description);
  e.pdvPeriodFlex = extractPdvPeriodFlexible(e.description);

  entries.push(e);
}

// ===== saldo check (preferiraj eksplicitno početno + završno) =====
// ===== SALDO: robustno iz rows (uključuje saldo-only linije) =====
function rowOrderKey(r) {
  const dk = parseDateKey(r.date || "");
  const ln = (r.lineNo ?? 0);
  return `${dk}|${String(ln).padStart(6, "0")}`;
}

// skupljaj sve redove koji imaju saldo broj (čak i ako su D=0/P=0)
const saldoCandidates = [];
for (const r of rows) {
  const desc = norm(r.description || r.rawLine || "");
  const DU = upper(desc);

  const s = (r.saldo === null || r.saldo === undefined || String(r.saldo).trim() === "")
    ? null
    : parseNum(r.saldo);

  if (!(typeof s === "number" && Number.isFinite(s))) continue;

  const d = parseNum(r.duguje);
  const p = parseNum(r.potrazuje);

  saldoCandidates.push({
    kind: isOpeningSaldoLine(DU) ? "OPENING"
        : isEndingSaldoLine(DU)   ? "ENDING"
        : (Math.abs(d) <= 0.0001 && Math.abs(p) <= 0.0001) ? "SALDO_ONLY"
        : "TXN_SALDO",
    saldo: s,
    order: rowOrderKey(r),
  });
}

// sort po vremenu/liniji
saldoCandidates.sort((a, b) => a.order.localeCompare(b.order));

// preferencije: eksplicitno > saldo-only > prvi/zadnji saldo kandidat
const openingExplicit = saldoCandidates.find(x => x.kind === "OPENING")?.saldo ?? null;
const endingExplicit  = [...saldoCandidates].reverse().find(x => x.kind === "ENDING")?.saldo ?? null;

const firstAnySaldo = saldoCandidates.length ? saldoCandidates[0].saldo : null;
const lastAnySaldo  = saldoCandidates.length ? saldoCandidates[saldoCandidates.length - 1].saldo : null;

let openingSaldo = openingExplicit ?? firstAnySaldo;
let endingSaldo  = endingExplicit  ?? lastAnySaldo;

// netAll i saldoCheck ostaju isti
const netAll = toFixed2(entries.reduce((s, e) => s + e.net, 0));

let saldoDelta = null;
let saldoOk = null;
let saldoDiff = 0;

if (openingSaldo != null && endingSaldo != null) {
  saldoDelta = toFixed2(endingSaldo - openingSaldo);
  saldoDiff = toFixed2(saldoDelta - netAll);
  saldoOk = (Math.abs(saldoDiff) <= 0.01);
}

const used = new Set();
const matchedPairs = [];

// ===== SPECIAL 239210: SUM IRA/URA per month =====
// ... tvoj match239210 dolje
function match239210(entries, used, matchedPairs) {
  if (accountNo !== "239210") return;

  const obveze = entries.filter(e => !used.has(e.idx) && isMonthlyObveza239210(e));
  if (!obveze.length) return;

  // sum of IRA/URA P by month from date
  const sumIraByPeriod = new Map();
  const iraByPeriod = new Map();

  for (const e of entries) {
    if (used.has(e.idx)) continue;
    if (!(e.potrazuje > 0 && e.duguje === 0)) continue;
    if (!isIraUra(e)) continue;
    const per = e.periodDate;
    if (!per) continue;

    sumIraByPeriod.set(per, toFixed2((sumIraByPeriod.get(per) || 0) + e.potrazuje));
    if (!iraByPeriod.has(per)) iraByPeriod.set(per, []);
    iraByPeriod.get(per).push(e);
  }

  for (const obv of obveze) {
    const per = obv.periodDescLong; // obveza mora imati MM/YYYY
    const iraList = iraByPeriod.get(per) || [];

    // sakrij IRA/URA redove tog perioda (da se ne vide u unmatched excelu)
    for (const p of iraList) used.add(p.idx);

    const sum = toFixed2(sumIraByPeriod.get(per) || 0);
    const diff = toFixed2(obv.duguje - sum);

    // spremi za excel stupce
    obv.period = per;
    obv.suma = sum;
    obv.diff = diff;

    if (iraList.length && Math.abs(diff) <= 0.01) {
      used.add(obv.idx);
      matchedPairs.push({ reason: "239210_SUM_OK", key: `239210|${per}`, a: obv, b: iraList[0] });
    } else {
      matchedPairs.push({
        reason: iraList.length ? "239210_SUM_MISMATCH" : "239210_NO_IRA",
        key: `239210|${per}|DIFF=${diff}`,
        a: obv,
        b: iraList[0] || obv,
      });
      // obv ostaje unmatched namjerno
    }
  }
}

match239210(entries, used, matchedPairs);

// ===== SPECIAL 239220: PDV period + amount pairing =====
function match239220(entries, used, matchedPairs) {
  if (accountNo !== "239220") return;

  const remaining = entries.filter(e => !used.has(e.idx));

  const dList = remaining.filter(e => e.duguje > 0 && e.potrazuje === 0);
  const pList = remaining.filter(e => e.potrazuje > 0 && e.duguje === 0);

  // Stage A: period + amount exact 1:1
  const map = new Map(); // key -> {d:[], p:[]}
  function add(side, e) {
    const per = e.pdvPeriodFlex; // YYYYMM from 01/25 or 01/2025
    if (!per) return;
    const key = `${per}|${e.amount}`;
    if (!map.has(key)) map.set(key, { d: [], p: [] });
    map.get(key)[side].push(e);
  }

  for (const e of dList) add("d", e);
  for (const e of pList) add("p", e);

  for (const [key, g] of map.entries()) {
    if (g.d.length === 1 && g.p.length === 1) {
      const a = g.d[0], b = g.p[0];
      if (used.has(a.idx) || used.has(b.idx)) continue;
      used.add(a.idx); used.add(b.idx);
      matchedPairs.push({ reason: "239220_PDV_PERIOD_AMT", key, a, b });
    }
  }

  // Stage B: amount-only unique 1:1 fallback for remaining
  const rem2 = entries.filter(e => !used.has(e.idx));
  const byAmt = new Map(); // amt -> {d:[], p:[]}
  for (const e of rem2) {
    if (e.duguje > 0 && e.potrazuje === 0) {
      if (!byAmt.has(e.amount)) byAmt.set(e.amount, { d: [], p: [] });
      byAmt.get(e.amount).d.push(e);
    } else if (e.potrazuje > 0 && e.duguje === 0) {
      if (!byAmt.has(e.amount)) byAmt.set(e.amount, { d: [], p: [] });
      byAmt.get(e.amount).p.push(e);
    }
  }

  for (const [amt, g] of byAmt.entries()) {
    if (g.d.length === 1 && g.p.length === 1) {
      const a = g.d[0], b = g.p[0];
      if (used.has(a.idx) || used.has(b.idx)) continue;
      used.add(a.idx); used.add(b.idx);
      matchedPairs.push({ reason: "239220_AMT_ONLY", key: `AMT|${amt}`, a, b });
    }
  }
}

match239220(entries, used, matchedPairs);

// ===== Generic matcher (UR/PN/DOC/PERSON/AMT) =====
function keysFor(e) {
  const keys = [];
  const a = e.amount;
  if (e.ur) keys.push(`UR|${a}|${e.ur}`);
  if (e.pn) keys.push(`PN|${a}|${e.pn}`);
  if (e.docNo) keys.push(`DOC|${a}|${e.docNo}`);
  if (e.person) keys.push(`PERSON|${a}|${e.person}`);
  if (e.person && !e.pn && !e.ur) keys.push(`PERSON_ONLY|${a}|${e.person}`);
  keys.push(`AMT|${a}`);
  return keys;
}

function buildIndex(list, prefix) {
  const map = new Map();
  for (const e of list) {
    for (const k of keysFor(e)) {
      if (prefix && !k.startsWith(prefix)) continue;
      if (!map.has(k)) map.set(k, []);
      map.get(k).push(e);
    }
  }
  return map;
}

// ===== SPECIAL 232910: "block sum" around CREDIT (POTRAŽUJE) =====
function match232910(entries, used, matchedPairs) {
  if (accountNo !== "232910") return;

  const remaining = entries.filter(e => !used.has(e.idx));
  const credits = remaining
    .filter(e => e.potrazuje > 0 && e.duguje === 0)
    .sort((a, b) => a.idx - b.idx);

  if (!credits.length) return;

  const tol = 0.01;

  function collectDebitsBetween(idxFromExclusive, idxToExclusive) {
    const list = [];
    for (const e of entries) {
      if (used.has(e.idx)) continue;
      if (!(e.duguje > 0 && e.potrazuje === 0)) continue;
      if (e.idx > idxFromExclusive && e.idx < idxToExclusive) list.push(e);
    }
    return list;
  }

  function sumDebits(list) {
    return toFixed2(list.reduce((s, e) => s + (e.duguje || 0), 0));
  }

  const creditIdxs = credits.map(c => c.idx);

  for (let i = 0; i < credits.length; i++) {
    const c = credits[i];
    if (used.has(c.idx)) continue;

    const prevCreditIdx = (i > 0) ? creditIdxs[i - 1] : -1;
    const nextCreditIdx = (i < credits.length - 1) ? creditIdxs[i + 1] : Number.POSITIVE_INFINITY;

    const creditAmt = toFixed2(c.potrazuje || 0);

    const debitsBefore = collectDebitsBetween(prevCreditIdx, c.idx);
    const sumBefore = sumDebits(debitsBefore);
    const diffBefore = toFixed2(creditAmt - sumBefore);

    if (debitsBefore.length && Math.abs(diffBefore) <= tol) {
      used.add(c.idx);
      for (const d of debitsBefore) used.add(d.idx);

      matchedPairs.push({
        reason: "232910_BLOCK_BEFORE",
        key: `232910|P=${creditAmt}|SUM=${sumBefore}|RANGE=(${prevCreditIdx},${c.idx})`,
        a: debitsBefore[0],
        b: c,
      });
      continue;
    }

    const debitsAfter = collectDebitsBetween(c.idx, nextCreditIdx);
    const sumAfter = sumDebits(debitsAfter);
    const diffAfter = toFixed2(creditAmt - sumAfter);

    if (debitsAfter.length && Math.abs(diffAfter) <= tol) {
      used.add(c.idx);
      for (const d of debitsAfter) used.add(d.idx);

      matchedPairs.push({
        reason: "232910_BLOCK_AFTER",
        key: `232910|P=${creditAmt}|SUM=${sumAfter}|RANGE=(${c.idx},${nextCreditIdx})`,
        a: c,
        b: debitsAfter[0],
      });
      continue;
    }
  }
}

match232910(entries, used, matchedPairs);

// ===== SPECIAL 239540: monthly transport group matcher =====

// --- helpers: period extraction ---

function extractDayMonthFromText(desc) {
  const t = norm(desc || "");
  // hvata 01.10. / 1.10. / 01.10 (bez zadnje točke)
  const m = t.match(/\b(\d{1,2})\.(\d{1,2})\.?\b/);
  if (!m) return null;
  const dd = String(m[1]).padStart(2, "0");
  const mm = String(m[2]).padStart(2, "0");
  return { dd, mm };
}

function extractYearFromDateStr(dateStr) {
  const s = String(dateStr || "").trim();
  const m = s.match(/^\d{1,2}\.\d{1,2}\.(\d{4})\.?$/);
  return m ? m[1] : null;
}

// key koji koristimo za grupiranje: YYYYMMDD
function deriveYyyyMmDdKeyFromDescAndEntry(desc, e) {
  const dm = extractDayMonthFromText(desc);
  if (!dm) return null;

  const yyyy =
    extractYearFromDateStr(e.date) ||
    (e.periodDate ? e.periodDate.slice(0, 4) : null);

  if (!yyyy) return null;
  return `${yyyy}${dm.mm}${dm.dd}`;
}

function isZrTrosakCredit(e) {
  // P red "Trošak refundiran djelatniku na ž-r 01.10."
  if (!(e.potrazuje > 0 && e.duguje === 0)) return false;
  const d = upper(e.description || "");
  return d.includes("TROŠAK") || d.includes("TROSAK") ? d.includes("Ž-R") || d.includes("Z-R") : false;
}

function isRefundDebitCandidate(e) {
  // D redovi tipično: "Izvod ... REF Refundacija zaposleniku - ref...."
  if (!(e.duguje > 0 && e.potrazuje === 0)) return false;
  const d = upper(e.description || "");
  return d.includes("IZVOD") && /\bREF\b/.test(d) && d.includes("REFUNDAC");
}

function extractIzvodId(desc) {
  const t = norm(desc || "");
  const m = t.match(/\bIzvod\s+(\d{2}\/\d{4,})\b/i);
  return m ? m[1] : null;
}

function normToken(s) {
  return upper(s || "")
    .replace(/[^\p{L}\p{N}\s]/gu, " ")   // makni znakove, ostavi slova/brojeve
    .replace(/\s+/g, " ")
    .trim();
}

function extractMerchantTokensFromDesc(desc) {
  // npr. "04.07. Chipoteka , links" -> ["CHIPOTEKA","LINKS"]
  let t = norm(desc || "");

  // makni vodeći datum (dd.mm. ili dd.mm.yyyy)
  t = t.replace(/^\s*\d{1,2}\.\d{1,2}\.(?:\d{2,4}\.)?\s*/i, "");

  // split po zarezima i " i " i "/" i "&"
  const parts = t
    .split(/,|\/|&|\s+\bi\b\s+/i)
    .map(x => normToken(x))
    .filter(x => x.length >= 3);

  // uniq
  return Array.from(new Set(parts));
}

function descHasAnyToken(desc, tokens) {
  const d = upper(desc || "");
  return tokens.some(tok => tok && d.includes(tok));
}

function descHasToken(desc, token) {
  const d = upper(desc || "");
  return token && d.includes(token);
}
function hasPrijevozExactWord(desc) {
  const d = upper(desc || "");
  // PRIJEVOZ, ali ne "PRIJEVOZA/PRIJEVOZU..."
  return /\bPRIJEVOZ(?![A-ZČĆŽŠĐ])/.test(d);
}

function hasPrijevozSummaryWord(desc) {
  const d = upper(desc || "");
  // summary smije biti "PRIJEVOZ" ili "PRIJEVOZA"
  return /\bPRIJEVOZ(A)?\b/.test(d);
}
function extractPeriodFromDateInText(desc) {
  const t = norm(desc);
  let m = t.match(/\b(\d{1,2})\.(\d{1,2})\.(\d{4})\.?\b/);
  if (m) return `${m[3]}${String(m[2]).padStart(2, "0")}`;
  m = t.match(/\b(\d{1,2})\.(\d{1,2})\.(\d{2})\.?\b/);
  if (m) return `20${m[3]}${String(m[2]).padStart(2, "0")}`;
  return null;
}
function extractMonthYearAnyFlex(desc) {
  return extractMonthYear(desc) || extractMonthYearShort(desc) || extractPeriodFromDateInText(desc);
}
function extractAnyPeriodToken(desc) {
  return extractMonthYear(desc) || extractMonthYearShort(desc) || null;
}

// PRIJEVOZ = točna riječ, ali dozvoli "PRIJEVOZ01/2025" (digits ok), ne dozvoli "PRIJEVOZA"
function hasTransportWord(desc) {
  const d = upper(desc || "");
  return /\bPRIJEVOZ(?![A-ZČĆŽŠĐ])/.test(d);
}

// Summary = kratak naslov ("Prijevoz 01/25").
// Sve "Izvod ... isp ..." su detail, nikad summary.
function is239540SummaryTransport(e) {
  const d = upper(e.description || "");

  // summary smije biti PRIJEVOZ ili PRIJEVOZA
  if (!hasPrijevozSummaryWord(d)) return false;

  const per = extractMonthYearAnyFlex(e.description) || e.periodDate;
  if (!per) return false;

  // izvod/isp su detail
  if (d.includes("IZVOD")) return false;
  if (/\bISP\.?\b/.test(d)) return false;

  // "refundacija prijevoza djelatnicima ..." je tipičan summary
  // (a i "Prijevoz 10/25" je summary)
  return d.length <= 120; // malo veći limit jer rečenica zna biti duža
}

function periodFor239540Detail(e) {
  return extractMonthYearAnyFlex(e.description) || e.periodDate || null;
}

// Detail:
// - mora imati riječ PRIJEVOZ (točno)
// - ako u opisu postoji MM/YY ili MM/YYYY -> mora biti baš taj period
// - inače fallback na date period
function is239540DetailTransport(e, period) {
  const desc = e.description || "";
  const d = upper(desc);

  if (!hasPrijevozExactWord(d)) return false;
  if (is239540SummaryTransport(e)) return false;

  const perInDesc = extractAnyPeriodToken(desc);
  if (perInDesc) return perInDesc === period;

  return e.periodDate === period;
}

function match239540TransportMonthlyGroups(entries, used, matchedPairs) {
  if (accountNo !== "239540") return;

  const tol = 0.01;

  // A) summaries + periods
  const summaries = entries
    .filter(e => !used.has(e.idx))
    .filter(e => is239540SummaryTransport(e));

  if (!summaries.length) return;

  const summaryPeriods = new Set();
  for (const s of summaries) {
    const per = extractMonthYearAnyFlex(s.description) || s.periodDate;
    if (per) summaryPeriods.add(per);
  }

  // B) LOCK: zaključaj sve detail kandidate perioda koji ima summary
  for (const e of entries) {
    if (used.has(e.idx)) continue;
    if (is239540SummaryTransport(e)) continue;
   if (!hasPrijevozExactWord(e.description)) continue;

    const per = periodFor239540Detail(e);
    if (per && summaryPeriods.has(per)) e._lock239540 = per;
  }

  // C) close each summary period
  for (const sumRow of summaries) {
    if (used.has(sumRow.idx)) continue;

    const period = extractMonthYearAnyFlex(sumRow.description) || sumRow.periodDate;
    if (!period) continue;

    const sumAmt = toFixed2(sumRow.amount);

    const members = entries
      .filter(e => !used.has(e.idx))
      .filter(e => is239540DetailTransport(e, period));

    if (!members.length) continue;

    const membersD = members.filter(e => e.duguje > 0 && e.potrazuje === 0);
    const membersP = members.filter(e => e.potrazuje > 0 && e.duguje === 0);

    const sumD = toFixed2(membersD.reduce((s, e) => s + (e.duguje || 0), 0));
    const sumP = toFixed2(membersP.reduce((s, e) => s + (e.potrazuje || 0), 0));

    function acceptMatchedPeriod(which, matchedSum) {
      used.add(sumRow.idx);
      for (const e of members) used.add(e.idx);
      for (const e of members) delete e._lock239540;

      matchedPairs.push({
        reason: "239540_GROUP_TRANSPORT_PERIOD_CLOSED",
        key: `239540|TRANSPORT|${period}|MATCH=${which}|SUM=${matchedSum}|MEMBERS=${members.length}`,
        a: sumRow,
        b: members[0] || sumRow,
      });
    }

    // match: summary može biti D ili P, ali koristimo absolute amount (sumRow.amount)
    const diffD = toFixed2(sumAmt - sumD);
    const diffP = toFixed2(sumAmt - sumP);

    const netPD = toFixed2(sumP - sumD);
    const diffNet = toFixed2(sumAmt - Math.abs(netPD));

    if (membersD.length && Math.abs(diffD) <= tol) { acceptMatchedPeriod("SUM_D", sumD); continue; }
    if (membersP.length && Math.abs(diffP) <= tol) { acceptMatchedPeriod("SUM_P", sumP); continue; }
    if (members.length  && Math.abs(diffNet) <= tol) { acceptMatchedPeriod("NET(P-D)", netPD); continue; }

    matchedPairs.push({
      reason: "239540_GROUP_TRANSPORT_NO_MATCH",
      key: `239540|TRANSPORT|${period}|SUM=${sumAmt}|sumD=${sumD}|sumP=${sumP}|net=${netPD}`,
      a: sumRow,
      b: members[0] || sumRow,
    });
  }
}

// IMPORTANT: call this BEFORE amount-only pairing
match239540TransportMonthlyGroups(entries, used, matchedPairs);

function match239540MultiNameCreditSum(entries, used, matchedPairs) {
  if (accountNo !== "239540") return;

  const tol = 0.01;

  // kandidati na P strani: potrazuje>0, opis ima bar 2 "merchant" tokena
  const creditCandidates = entries
    .filter(e => !used.has(e.idx))
    .filter(e => e.potrazuje > 0 && e.duguje === 0)
    .map(e => ({ e, tokens: extractMerchantTokensFromDesc(e.description) }))
    .filter(x => x.tokens.length >= 2);

  if (!creditCandidates.length) return;

  // pripremi D refund redove (duguje>0) koji imaju RN/ref/izvod (da ne kupimo svašta)
  const debitCandidates = entries
    .filter(e => !used.has(e.idx))
    .filter(e => e.duguje > 0 && e.potrazuje === 0)
    .filter(e => /\bREF\b/i.test(e.description) || /\bRN\b/i.test(e.description) || /\bIzvod\b/i.test(e.description));

  for (const { e: credit, tokens } of creditCandidates) {
    if (used.has(credit.idx)) continue;

    const creditAmt = toFixed2(credit.potrazuje || 0);
    const creditPeriod = credit.periodDate || extractMonthYearAnyFlex(credit.description);
    const creditIzvod = extractIzvodId(credit.description); // često null

    // 1) kandidati na D strani: isti period (ako znamo period) + sadrže bar jedan token
    let cands = debitCandidates.filter(d => {
      if (used.has(d.idx)) return false;
      if (creditPeriod && d.periodDate && d.periodDate !== creditPeriod) return false;
      return descHasAnyToken(d.description, tokens);
    });

    if (!cands.length) continue;

    // 2) ako D redovi imaju izvod id i većina dijeli isti izvod -> ograniči na taj izvod
    // (ovo sprječava slučajno miješanje dva izvoda istog mjeseca)
    const izvodCounts = new Map();
    for (const d of cands) {
      const iz = extractIzvodId(d.description);
      if (!iz) continue;
      izvodCounts.set(iz, (izvodCounts.get(iz) || 0) + 1);
    }

    // ako credit ima izvod, koristi njega; inače uzmi najčešći izvod ako postoji
    let targetIzvod = creditIzvod || null;
    if (!targetIzvod && izvodCounts.size) {
      targetIzvod = Array.from(izvodCounts.entries()).sort((a,b)=>b[1]-a[1])[0][0];
    }
    if (targetIzvod) {
      const filtered = cands.filter(d => extractIzvodId(d.description) === targetIzvod);
      if (filtered.length) cands = filtered;
    }

    // 3) greedy: uzmi samo one D redove koji pokrivaju sve tokene (bar 1 po tokenu)
    // i provjeri sumu
    const chosen = [];
    const covered = new Set();

    // sortiraj po idx da bude deterministično
    cands.sort((a,b)=>a.idx-b.idx);

    for (const d of cands) {
      // dodaj ako doprinosi pokrivanju tokena
      let addsCoverage = false;
      for (const t of tokens) {
        if (!covered.has(t) && descHasToken(d.description, t)) {
          addsCoverage = true;
          break;
        }
      }
      if (addsCoverage) {
        chosen.push(d);
        for (const t of tokens) if (descHasToken(d.description, t)) covered.add(t);
      }
      if (covered.size === tokens.length) break;
    }

    // ako nismo pokrili sve tokene, ipak možemo pokušati sumirati sve cands (nekad tokeni nisu 1:1)
    // ali samo ako suma točno sjedne
    function tryCloseWith(list, reasonKey) {
      const sumD = toFixed2(list.reduce((s,x)=>s+(x.duguje||0),0));
      if (Math.abs(sumD - creditAmt) > tol) return false;

      used.add(credit.idx);
      for (const d of list) used.add(d.idx);

      matchedPairs.push({
        reason: "239540_MULTI_NAME_SUM",
        key: `239540|MULTI|PER=${creditPeriod||"?"}|IZ=${targetIzvod||"?"}|TOKENS=${tokens.join("+")}|SUMD=${sumD}|P=${creditAmt}|MODE=${reasonKey}`,
        a: credit,
        b: list[0] || credit,
      });
      return true;
    }

    // prvo pokušaj s “chosen” ako pokriva sve tokene
    if (covered.size === tokens.length && chosen.length) {
      if (tryCloseWith(chosen, "COVER_ALL_TOKENS")) continue;
    }

    // fallback: probaj sa svim kandidatima (za slučaj da isti vendor nije spomenut u svakom redu ili su tokeni “noisy”)
    if (tryCloseWith(cands, "ALL_CANDS")) continue;
  }
}
match239540TransportMonthlyGroups(entries, used, matchedPairs);
match239540MultiNameCreditSum(entries, used, matchedPairs);   // <-- NOVO
match239540(entries, used, matchedPairs);

function match239540ZrTrosakByDay(entries, used, matchedPairs) {
  if (accountNo !== "239540") return;

  const tol = 0.01;

  // 1) grupiraj P "Trošak ... ž-r dd.mm." po YYYYMMDD i (ako postoji) Izvodu
  const creditGroups = new Map(); // key -> { credits:[], sumP }
  for (const e of entries) {
    if (used.has(e.idx)) continue;
    if (!isZrTrosakCredit(e)) continue;

    const dayKey = deriveYyyyMmDdKeyFromDescAndEntry(e.description, e);
    if (!dayKey) continue;

    const izvod = extractIzvodId(e.description) || ""; // često nema na toj liniji
    const key = `${dayKey}|IZ=${izvod}`;

    if (!creditGroups.has(key)) creditGroups.set(key, { dayKey, izvod, credits: [], sumP: 0 });
    const g = creditGroups.get(key);
    g.credits.push(e);
    g.sumP = toFixed2(g.sumP + (e.potrazuje || 0));
  }

  if (!creditGroups.size) return;

  // 2) indexiraj D refund stavke po YYYYMMDD i Izvodu
  const debitGroups = new Map(); // key -> { debits:[], sumD }
  for (const e of entries) {
    if (used.has(e.idx)) continue;
    if (!isRefundDebitCandidate(e)) continue;

    // datum je pouzdaniji iz e.date (jer D red ima pun datum)
    const dayKey = (e.dateKey && /^\d{8}$/.test(e.dateKey)) ? e.dateKey : null;
    if (!dayKey) continue;

    const izvod = extractIzvodId(e.description) || "";
    const key = `${dayKey}|IZ=${izvod}`;

    if (!debitGroups.has(key)) debitGroups.set(key, { dayKey, izvod, debits: [], sumD: 0 });
    const g = debitGroups.get(key);
    g.debits.push(e);
    g.sumD = toFixed2(g.sumD + (e.duguje || 0));
  }

  // 3) pokušaj match: prvo striktno (isti dayKey + isti izvod), pa fallback (isti dayKey bilo koji izvod)
  for (const [ckey, cg] of creditGroups.entries()) {
    // skip ako su već used (u međuvremenu)
    cg.credits = cg.credits.filter(x => !used.has(x.idx));
    if (!cg.credits.length) continue;

    const creditSum = cg.sumP;

    // A) striktno: isti IZ (ako ga imamo)
    let matchKey = `${cg.dayKey}|IZ=${cg.izvod}`;
