        dg = candidates.find(x => Math.abs(toFixed2(x.sumD - creditSum)) <= tol) || null;
      }
    }

    if (!dg || !dg.debits.length) continue;

    // sum check
    if (Math.abs(toFixed2(dg.sumD - creditSum)) > tol) continue;

    // mark used
    for (const c of cg.credits) used.add(c.idx);
    for (const d of dg.debits) used.add(d.idx);

    matchedPairs.push({
      reason: "239540_ZR_TROSAK_BY_DAY_SUM",
      key: `239540|ZR|DAY=${cg.dayKey}|IZ=${dg.izvod || "?"}|P=${creditSum}|D=${dg.sumD}|C=${cg.credits.length}|Dcnt=${dg.debits.length}`,
      a: cg.credits[0],
      b: dg.debits[0] || cg.credits[0],
    });
  }
}

