    if (used.has(e.idx)) continue;
    if (e._lock239540) continue; // poštuj lock od prijevoza perioda
    if (!(e.potrazuje > 0 && e.duguje === 0)) continue;

    // ako želiš: izbjegni P redove koji sami sadrže "Izvod" (da ne radimo duplo)
    // if (/\bIZVOD\b/i.test(e.description)) continue;

    const a = toFixed2(e.potrazuje || 0);
    if (!pByAmt.has(a)) pByAmt.set(a, []);
    pByAmt.get(a).push(e);
  }

