  function findCreditByAmount(target) {
    const t = toFixed2(target);
    if (pByAmt.has(t) && pByAmt.get(t).length) return pByAmt.get(t)[0];

    // fallback: probaj +/- 0.01 (rijetko potrebno, ali sigurno)
    const tPlus = toFixed2(t + 0.01);
    if (pByAmt.has(tPlus) && pByAmt.get(tPlus).length) return pByAmt.get(tPlus)[0];
    const tMinus = toFixed2(t - 0.01);
    if (pByAmt.has(tMinus) && pByAmt.get(tMinus).length) return pByAmt.get(tMinus)[0];

    return null;
  }

  // 3) za svaki izvod zbroji D i pokušaj naći P
  // sortiraj izvod groups deterministično
  const izvodList = Array.from(dByIzvod.entries()).sort((a, b) => a[0].localeCompare(b[0]));

