    if (!debits.length) continue;

    const sumD = toFixed2(debits.reduce((s, x) => s + (x.duguje || 0), 0));
    if (sumD <= 0) continue;

    const credit = findCreditByAmount(sumD);
    if (!credit) continue;

    // dodatna zaštita: ne spajaj ako je credit u drugom mjesecu (ako oba imaju periodDate)
    // (smanjuje slučajne match-eve kad je isti iznos čest)
    if (credit.periodDate && debits[0].periodDate && credit.periodDate !== debits[0].periodDate) {
      continue;
    }

    // mark used
    for (const d of debits) used.add(d.idx);
    used.add(credit.idx);

    // makni credit iz indeksa da ga ne koristimo opet
    const ca = toFixed2(credit.potrazuje || 0);
    if (pByAmt.has(ca)) {
      pByAmt.set(ca, pByAmt.get(ca).filter(x => x.idx !== credit.idx));
      if (!pByAmt.get(ca).length) pByAmt.delete(ca);
    }

    matchedPairs.push({
      reason: "239540_IZVOD_DEBIT_SUM_TO_CREDIT",
      key: `239540|IZVOD|${iz}|SUMD=${sumD}|P=${ca}|DEBITS=${debits.length}`,
      a: credit,
      b: debits[0] || credit,
    });
  }
