    if (!groups.has(a)) groups.set(a, { d: [], p: [] });

    if (e.duguje > 0 && e.potrazuje === 0) groups.get(a).d.push(e);
    else if (e.potrazuje > 0 && e.duguje === 0) groups.get(a).p.push(e);
  }

  for (const [amt, g] of groups.entries()) {
    const dList = g.d.sort((x, y) => x.idx - y.idx);
    const pList = g.p.sort((x, y) => x.idx - y.idx);

    const n = Math.min(dList.length, pList.length);
    if (n <= 0) continue;

    for (let i = 0; i < n; i++) {
      const d = dList[i];
      const p = pList[i];
      if (used.has(d.idx) || used.has(p.idx)) continue;

      used.add(d.idx);
      used.add(p.idx);

      matchedPairs.push({
        reason: "239540_AMT_ONLY",
        key: `239540|AMT|${amt}`,
        a: d,
        b: p,
      });
    }
  }
