//232370 matchanje-helperi

function extractIzvodId(desc) {
  const t = norm(desc || "");
  // hvata "Izvod 25/15262" i "IZVOD 25/15262"
  const m = t.match(/\bIzvod\s+(\d{2}\/\d{4,})\b/i);
  return m ? m[1] : null;
}

function match232370IzvodDebitSumToCredit(entries, used, matchedPairs) {
  if (accountNo !== "232370") return;

  const tol = 0.01;

  // 1) grupiraj DUGUJE po IZVODU (uzima sve s duguje>0, bez uvjeta potrazuje===0)
  const dByIzvod = new Map(); // izvod -> [entries]
  for (const e of entries) {
    if (used.has(e.idx)) continue;
    if (!(e.duguje > 0)) continue;

    const iz = extractIzvodId(e.description);
    if (!iz) continue;

    const d = upper(e.description || "");
    // ciljamo AH blokove (AUTORSKI HONORAR), ali dovoljno je "AH"
    if (!/\bAH\b/.test(d) && !d.includes("AUTORSKI")) continue;

    if (!dByIzvod.has(iz)) dByIzvod.set(iz, []);
    dByIzvod.get(iz).push(e);
  }
  if (!dByIzvod.size) return;

  // 2) index POTRAŽUJE po iznosu (preferiraj opise koji počinju s "AH")
  const pByAmt = new Map(); // amt -> [entries]
  for (const e of entries) {
    if (used.has(e.idx)) continue;
    if (!(e.potrazuje > 0)) continue;
    if (e.duguje > 0) continue; // credit red mora biti "čisti" P

    const amt = toFixed2(e.potrazuje || 0);
    if (!pByAmt.has(amt)) pByAmt.set(amt, []);
    pByAmt.get(amt).push(e);
  }

  for (const list of pByAmt.values()) {
    // preferiraj one koji počinju s "AH"
    list.sort((a, b) => {
      const aAh = /^\s*AH\b/i.test(a.description || "") ? 0 : 1;
      const bAh = /^\s*AH\b/i.test(b.description || "") ? 0 : 1;
      if (aAh !== bAh) return aAh - bAh;
      return a.idx - b.idx;
    });
  }

  // 3) pokušaj match za svaki izvod
  const izvodList = Array.from(dByIzvod.entries()).sort((a, b) => a[0].localeCompare(b[0]));
  for (const [iz, list] of izvodList) {
    const debits = list.filter(x => !used.has(x.idx));
    if (!debits.length) continue;

    const sumD = toFixed2(debits.reduce((s, x) => s + (x.duguje || 0), 0));
    if (sumD <= 0) continue;

    const credits = pByAmt.get(sumD);
    if (!credits || !credits.length) continue;

    const credit = credits[0];

    // mark used
    for (const d of debits) used.add(d.idx);
    used.add(credit.idx);

    // remove credit from index
    pByAmt.set(sumD, credits.filter(x => x.idx !== credit.idx));
    if (!pByAmt.get(sumD).length) pByAmt.delete(sumD);

    matchedPairs.push({
      reason: "232370_IZVOD_DEBIT_SUM_TO_CREDIT",
      key: `232370|IZVOD|${iz}|SUMD=${sumD}|DEBITS=${debits.length}`,
      a: credit,
      b: debits[0] || credit,
    });
  }
}


