//match 232110

function foldCroatian(s) {
  return upper(s || "")
    .replace(/Č/g, "C").replace(/Ć/g, "C")
    .replace(/Š/g, "S").replace(/Ž/g, "Z")
    .replace(/Đ/g, "D");
}

// 232110: izvuci osobu pouzdano (uzima ZADNJE ime/prezime iz reda)
function extractPersonKey232110(desc) {
  let t = norm(desc || "");
  if (!t) return null;

  // makni prefiks tipa "25/38 " ili "258/25 "
  t = t.replace(/^\s*\d{1,4}\s*\/\s*\d{1,6}\s+/i, "").trim();

  // makni "Izvod ... isp. ..." boilerplate (ne mora biti savršen, bitno je ne smeta imenu na kraju)
  t = t.replace(/\bIzvod\s+\d{2}\/\d{4,}\b/ig, " ");
  t = t.replace(/\bisp\.?\s*\d+\b/ig, " ");

  // ako ima crtica-separatora, uzmi rep nakon zadnje " - "
  // (ime je praktički uvijek na kraju nakon zadnjeg "-")
  const lastDash = t.lastIndexOf(" - ");
  if (lastDash >= 0 && lastDash < t.length - 3) {
    t = t.slice(lastDash + 3).trim();
  } else {
    // fallback: ako su crtice bez razmaka
    const lastDash2 = t.lastIndexOf("-");
    if (lastDash2 >= 0 && lastDash2 < t.length - 1) t = t.slice(lastDash2 + 1).trim();
  }

  // tokenizacija (izbaci brojeve i interpunkciju)
  const stop = new Set([
    "IZVOD","ISP","PN","PUTNI","NALOZI","ISPLATA","PUTNIH","NALOGA","NALOG",
    "REF","RN","UR","URR","URA","UPLATA","HO","AH"
  ]);

  const words = t
    .replace(/[0-9]/g, " ")
    .replace(/[.,;:()\-_/]/g, " ")
    .split(/\s+/)
    .filter(Boolean)
    .map(w => foldCroatian(w))
    .filter(w => w.length >= 3 && /^[A-Z]+$/.test(w) && !stop.has(w));

  if (!words.length) return null;

  // FULL: zadnje dvije riječi, SINGLE: zadnja riječ
  if (words.length >= 2) {
    const w1 = words[words.length - 2];
    const w2 = words[words.length - 1];
    return { key: `${w1} ${w2}`, kind: "FULL" };
  }
  return { key: words[words.length - 1], kind: "SINGLE" };
}


function match232110ByPersonAndAmount(entries, used, matchedPairs) {
  if (accountNo !== "232110") return;

  const tol = 0.01;

  const ZERO_TOL = 0.01;

function isPureD(e) {
  return (e.duguje > 0 && (e.potrazuje || 0) <= ZERO_TOL) || (e.net > 0);
}
function isPureP(e) {
  return (e.potrazuje > 0 && (e.duguje || 0) <= ZERO_TOL) || (e.net < 0);
}

  // ---------- PASS 1: FULL↔FULL by amount (unique 1:1) ----------
// PASS 1: (FULL ili SINGLE) ↔ (FULL ili SINGLE) by amount (unique 1:1)
