      const pRem = pArr.filter(x => !used.has(x.idx)).sort((a,b)=>a.idx-b.idx);

      if (!dRem.length || !pRem.length) continue;

      // Only zip when counts match exactly (prevents wrong steals)
      if (dRem.length !== pRem.length) continue;

      for (let i = 0; i < dRem.length; i++) {
