      for (const x of list) {
        if (used.has(x.e.idx)) continue;

        if (!cluster.length) {
          cluster = [x];
          minIdx = maxIdx = x.e.idx;
          continue;
        }

        const newMin = Math.min(minIdx, x.e.idx);
        const newMax = Math.max(maxIdx, x.e.idx);

        if ((newMax - newMin) <= CLUSTER_MAX_SPAN) {
          cluster.push(x);
          minIdx = newMin;
          maxIdx = newMax;
        } else {
          // close current cluster and start new
          flushCluster();
          cluster = [x];
          minIdx = maxIdx = x.e.idx;
        }
      }

      flushCluster();
    }
  }

  // ---------- PASS 3: GROUP-SUM by FULL person (and safe SINGLE) ----------
  {
    const rem = entries.filter(e => !used.has(e.idx));
    const dList = rem.filter(isPureD);
    const pList = rem.filter(isPureP);

    const gD = new Map(), gP = new Map(); // k -> {kind,key,list,sum}

    function addGroup(map, e, side){
      const pk = extractPersonKey232110(e.description);
      if (!pk) return;
      const k = `${pk.kind}|${pk.key}`;
      if (!map.has(k)) map.set(k, {kind:pk.kind, key:pk.key, list:[], sum:0});
      const g = map.get(k);
      g.list.push(e);
      g.sum = toFixed2(g.sum + (side==="D" ? e.duguje : e.potrazuje));
    }

    for (const e of dList) addGroup(gD, e, "D");
    for (const e of pList) addGroup(gP, e, "P");

    // safe SINGLE: token se ne smije pojaviti u 2+ FULL imena
    const fullTokenCount = new Map();
    function countFullTokens(map){
      for (const g of map.values()) {
        if (g.kind !== "FULL") continue;
        for (const t of foldCroatian(g.key).split(/\s+/)) {
          fullTokenCount.set(t, (fullTokenCount.get(t)||0)+1);
        }
      }
    }
    countFullTokens(gD); countFullTokens(gP);
    function singleSafe(tok){ return (fullTokenCount.get(tok)||0) <= 1; }

    for (const [k, gd] of gD.entries()) {
      const gp = gP.get(k);
      if (!gp) continue;

      if (gd.kind === "FULL") {
        if (Math.abs(toFixed2(gd.sum - gp.sum)) <= tol) {
          for (const e of gd.list) used.add(e.idx);
          for (const e of gp.list) used.add(e.idx);
          matchedPairs.push({
            reason:"232110_PERSON_GROUP_SUM",
            key:`FULL|${gd.key}|SUMD=${gd.sum}|SUMP=${gp.sum}|D=${gd.list.length}|P=${gp.list.length}`,
            a: gd.list[0],
            b: gp.list[0] || gd.list[0]
          });
        }
      } else if (gd.kind === "SINGLE" && singleSafe(gd.key)) {
        if (Math.abs(toFixed2(gd.sum - gp.sum)) <= tol) {
          for (const e of gd.list) used.add(e.idx);
          for (const e of gp.list) used.add(e.idx);
          matchedPairs.push({
            reason:"232110_SINGLE_GROUP_SUM",
            key:`SINGLE|${gd.key}|SUMD=${gd.sum}|SUMP=${gp.sum}|D=${gd.list.length}|P=${gp.list.length}`,
            a: gd.list[0],
            b: gp.list[0] || gd.list[0]
          });
        }
      }
    }
  }
}

match232110ByPersonAndAmount(entries, used, matchedPairs);

function matchAmountOnlyUnique(entries, used, matchedPairs, reasonTag) {
  const remaining = entries.filter(e => !used.has(e.idx) && !e._lock239540);

  const dByAmt = new Map();
  const pByAmt = new Map();

  for (const e of remaining) {
    if (e.duguje > 0 && e.potrazuje === 0) {
      const a = e.amount;
      if (!dByAmt.has(a)) dByAmt.set(a, []);
      dByAmt.get(a).push(e);
    } else if (e.potrazuje > 0 && e.duguje === 0) {
      const a = e.amount;
      if (!pByAmt.has(a)) pByAmt.set(a, []);
      pByAmt.get(a).push(e);
    }
  }

  for (const [amt, dList] of dByAmt.entries()) {
    const pList = pByAmt.get(amt) || [];
    if (dList.length === 1 && pList.length === 1) {
      const d = dList[0], p = pList[0];
      if (used.has(d.idx) || used.has(p.idx)) continue;
      used.add(d.idx);
      used.add(p.idx);
      matchedPairs.push({
        reason: reasonTag || "AMT_ONLY_UNIQUE",
        key: `AMT_ONLY|${amt}`,
        a: d,
        b: p,
      });
    }
  }
}





function matchUnique(prefix) {
  const idx = buildIndex(entries.filter(e => !used.has(e.idx) && !e._lock239540), prefix);
  for (const [k, list] of idx.entries()) {
    if (list.length !== 2) continue;
    const a = list[0], b = list[1];
    if (used.has(a.idx) || used.has(b.idx)) continue;
    used.add(a.idx); used.add(b.idx);
    matchedPairs.push({ reason: prefix.replace("|","").replace(/\|.*/,""), key: k, a, b });
  }
}

