function money(n) {
  if (n === null || n === undefined || !Number.isFinite(Number(n))) return '';
  const x = Number(n);
  const fixed = x.toFixed(2);
  const [a, b] = fixed.split('.');
  const withThousands = a.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return `${withThousands},${b}`;
}

function clean(s) {
  return (s ?? '').toString().replace(/\s+/g, ' ').trim();
}

function escHtml(s) {
  return (s ?? '')
    .toString()
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function sideLabel(side) {
  if (side === 'D') return 'DUGUJE';
  if (side === 'P') return 'POTRAŽUJE';
  return side || '';
}

function is239210ObvezaRow(accNo, u) {
  if (String(accNo) !== '239210') return true;
  const desc = clean(u?.desc || '');
  const hasPeriod = /\b[0-1]?\d\/20\d{2}\b/.test(desc);
  const isIra = /\b(IRA|URA)\b/i.test(desc);
  return hasPeriod && !isIra;
}

function toFixed2(n) {
  if (!Number.isFinite(Number(n))) return null;
  return Math.round((Number(n) + Number.EPSILON) * 100) / 100;
}

function eqTol(a, b, tol = 0.01) {
  if (a == null || b == null) return null;
  return Math.abs(toFixed2(a) - toFixed2(b)) <= tol;
}

